{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "For FFY26 (10/1/2025-9/30/2026), gross annual household income must be at or below: 1: $37,439; 2: $48,959; 3: $60,479; 4: $71,999; 5: $83,518; 6: $95,038; 7: $97,198 (monthly equivalents: 1: $3,743; 2: $4,895; 3: $6,047; 4: $7,199; 5: $8,351; 6: $9,503). Larger households contact local provider. Based on 50% State Median Income.[1][2][3][4]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Must live in Minnesota.", "Household includes all at address sharing utility bill.", "Income based on past month or prior year tax forms for self-employment."][2][3][5]
  },
  "benefits": {
    "type": "financial",
    "value": "Regular (Primary Heat): $200 min to $1,400 max, paid directly to utility. Crisis (Winter): up to $600; Summer: not available. Varies by income, size, fuel type, heating costs.[1][4]",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": ["Online: https://energy-assistance.web.commerce.state.mn.us (exceptions: Safe at Home participants, reapplicants for 2025-2026 cannot use).", "Phone: 1-800-657-3710 or 651-296-2860 (TTY). Local providers (e.g., Hennepin: 952-930-3541).", "Mail or in-person: To local Energy Assistance Provider (EAP agency). Download application from local provider or state site."],
    "processing_time": "Within a month of applying.[2]",
    "waitlist": "Funding limited; agencies may stop accepting if funds run out before May 31.[1][2][5]",
    "forms": ["Energy Assistance Program (EAP) application (download from local provider or state site)."],
    "documents": ["Proof of income (past 3 months: pay stubs, benefit notices, tax forms).", "Heating/electric provider name and account number.", "Most recent energy bills.", "For no income/self-employed: contact provider."][2][3][4]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide via local providers.",
    "regional_variations": "Administered by local EAP agencies (e.g., Community Action Partnership in Hennepin County); income tables may have minor local presentation differences; contact local office for larger households or specifics.[3][4]",
    "offices_or_providers": ["Local EAP agencies; find via 1-800-657-3710 or state site."]
  },
  "official_source": "https://mn.gov/commerce/energy/consumer-assistance/energy-assistance-program/guidelines.jsp",
  "gotchas": ["Funding runs out before May 31; apply early.", "Online application unavailable for Safe at Home or 2025-2026 reapplicants.", "Household includes all sharing utility bill (unlike SNAP).", "Crisis requires immediate emergency (e.g., shutoff, low fuel, or 60+ with bill).", "Program year Oct 1-May 31; separate weatherization program."[1][2][4][5]],
  "data_shape_notes": "Statewide but local providers administer; benefits scale by household size, income, fuel; two tiers (regular/crisis); funding-limited with early closeouts."
}

{
  "name": "Senior Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, including those under age 65 with disabilities and dually eligible for Medicare and Medicaid[1][3][5]",
    "asset_limits": "No asset limits or tests apply[3]",
    "other_requirements": ["Must be a Medicare beneficiary or family/caregiver of one[1][3][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one personalized counseling and assistance on Medicare options (Parts A, B, C, D), Medigap, Medicare Savings Programs, Extra Help/Low Income Subsidy, Medicaid issues, long-term care insurance, appeals, coverage decisions, and fraud prevention via Senior Medicare Patrol; also includes public education presentations, outreach at events, and information on rights/protections[1][3][4][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free (800) 333-2433[2][7][8]", "Website: www.mnaging.org or www.minnesotahelp.info[7][8]", "In-person or mail via local Area Agencies on Aging or Senior LinkAge Line sites statewide[1][2]"],
    "processing_time": "Immediate counseling available via phone or in-person; no formal application processing[3][4]",
    "waitlist": null,
    "forms": ["No specific forms required; counseling provided directly[3]"],
    "documents": ["Medicare card, current insurance details, prescription list, and income info if applying for savings programs during counseling[3][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered through Minnesota Board on Aging, Area Agencies on Aging, and over 2,200 local sites with locally focused counseling reflecting regional Medicare options, providers, and resources; no differences in eligibility or benefits[1][2][5]",
    "offices_or_providers": ["Minnesota Board on Aging, 540 Cedar Street, P.O. Box 64976, St. Paul, MN 55164-0976; local Area Agencies on Aging[1][2]"]
  },
  "official_source": "https://mn.gov/adresources/search/f7c7358c-7c36-5ce3-bfac-c412310ca4c5[6]",
  "gotchas": ["Not a financial aid or direct payment program—only free counseling and education, no coverage or premiums paid; funding risks from federal budgets can impact availability; end of Medicare Cost plans in some years required plan changes[1][3][4]", "Must contact via Senior LinkAge Line for Minnesota-specific service, not generic national SHIP[1][2][7]"],
  "data_shape_notes": "no income test; counseling only, no direct benefits; delivered via statewide Senior LinkAge Line network of local Area Agencies on Aging with volunteer counselors[1][3][5]"
}

