{
  "name": "Minnesota Aging Pathways (formerly Senior LinkAge Line)",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income or asset limits for Minnesota Aging Pathways itself; it is a free information, referral, and counseling service open to older adults, caregivers, and families. For referred long-term care services (e.g., home care or nursing facility), eligibility is determined separately by county social services or managed care organizations with varying income/asset rules, such as Medicaid limits (e.g., 2026 single nursing home applicant: income under $1,305/month, assets under $3,000).[1][4][5]",
    "asset_limits": "No asset limits for the core service; asset rules apply only to specific publicly funded programs accessed via referral (e.g., Medicaid excludes primary home, one vehicle, personal belongings; countable assets include secondary properties, excess cash).[1]",
    "other_requirements": ["Minnesota resident", "Typically age 60+ or Medicare-eligible for counseling", "For resource coordination: in home or community setting, may need nursing home level of care assessment for transitions", "Preadmission screening (PAS) required for nursing facility admissions regardless of finances[2][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free information and assistance (I&A), Medicare counseling (SHINE-certified), resource coordination (person-centered plans to stay/return home, service connections, caregiver support), preadmission screening (PAS) for nursing facilities, long-term care options counseling (required for assisted living moves), referrals to Minnesota Aging and Disability Resources, financing options guidance. No fixed dollar amounts or hours; support is in-depth as needed with follow-up.[2][4][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-333-2433 (Mon-Fri 8:00 a.m. to 4:30 p.m.; press option 1 for housing)", "Online referral: www.sllreferral.org (for providers, facilities, caregivers)", "Referrals from nursing facilities, hospitals, assisted living, clinics, home care, hospice, ombudsman[5][6]"],
    "processing_time": "Phone assistance immediate; resource coordination involves discussion and plan development (typically prompt follow-up after referral); PAS review leads to in-person county assessment or call as needed[2][5]",
    "waitlist": null,
    "forms": ["Preadmission Screening (PAS) submitted by providers", "Online referral form at www.sllreferral.org[2][5]"],
    "documents": ["No specific documents for initial call or I&A; for PAS or resource coordination: medical info, MDS assessments if applicable, preferences for care setting. Prepare ID, Medicare info, service needs for counseling[2][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Statewide service, but post-referral long-term care handled by local county social services or area agencies on aging (e.g., MN River Area Agency); PAS may involve county in-person assessments; no noted wait time differences[2][5][7][8]",
    "offices_or_providers": ["Statewide phone/online; partners with Minnesota Board on Aging and area agencies on aging[7]"]
  },
  "official_source": "https://mn.gov/aging-pathways/",
  "gotchas": ["Not a direct service provider—offers info/referrals only; actual eligibility/funding for home care etc. determined by counties/managed care, not Aging Pathways[4]", "Required for nursing facility admissions (PAS) and assisted living moves (options counseling)—providers must refer[2][5]", "Free but no guaranteed service hours or funding; for low-income, refers to separate eligibility processes[4][7]", "Name change from Senior LinkAge Line may confuse searches[6]"],
  "data_shape_notes": "no income test for core I&A/counseling; eligibility only for referred paid services; statewide free access via single phone line with local handoffs; mandatory gateway for facility transitions"
}
